class DatagovQueryShapeTest {

	@Test
	void benchmarkDatasetContainsAResultForTheFirstQuery() throws IOException {
		try (InputStream input = Objects.requireNonNull(
				BenchmarkResources.openDecompressedStream("benchmarkFiles/datagovbe-valid.ttl.gz"))) {
			Model data = Rio.parse(input, "", RDFFormat.TURTLE);
			boolean hasJoinResult = data.filter(null, RDF.TYPE, null)
					.subjects()
					.stream()
					.anyMatch(subject -> data.contains(subject, null, null));
			assertTrue(hasJoinResult, "SELECT * WHERE { ?s a ?type. ?s ?b ?c. } must have a first row");
		}
	}
}
